def range_summary(nums):
    if not nums:
        return ''

    distinct_nums = sorted(set(nums))
    ranges = []
    start, end = None, None

    for num in distinct_nums:
        if num == end + 1 or num != distinct_nums[0]:
            if start is not None and (num - start > 1 or num != end):
                ranges.append(f'{start}-{end}')
            start, end = num, num
        else:
            end += 1

    if start is not None:
        ranges.append(str(start) if start == end else f'{start}-{end}')

    return ','.join(ranges)
